('00185df2-865f-4da6-8df1-8ef8b7c0a578', '9e2a9f31-bce3-48ff-b438-0a00f8f8ec0b', 'ROSSO-15SW800', 0, 0, '0829acf6-a413-48bd-98a3-de816ea9e77b', '2025-09-17 07:01:22.252', '2026-05-29 08:45:59.544', '<ul><li><p>Proprietary cone paper material made in-house</p></li><li><p>Minimum damping fiber glass voice coil former</p></li><li><p>4\" voice coil with APC (Advanced Polymer Coating)</p></li><li><p>Ribbon voice coil wire for high efficiency</p></li><li><p>Cast aluminium chassis</p></li><li><p>Vented pole piece for reduced compression</p></li></ul>', 'rosso-15sw800', 'admin', 0, '', 0, '', '', '', 0, '/uploads/productimage/ROSSO-15SW800.webp', '/uploads/productdrawing/ROSSO-15SW800-drawing.jpg', '/uploads/productfrequencyresponse/ROSSO-15SW800-frequency response.jpg', ''),
('01ff6b88-eeca-4bf3-8cf2-7276fcdd4a2e', '9e2a9f31-bce3-48ff-b438-0a00f8f8ec0b', 'ROSSO-65CD-T', 0, 0, '3aa615e1-7464-49b0-aefe-19cb5ab117df', '2025-09-15 07:49:58.052', '2026-04-17 04:10:39.781', '<ul><li><p>Titanium diaphragm</p></li><li><p>Copper cap for reduced distortion and extended HF response</p></li><li><p>Extended upper frequency response</p></li><li><p>Advanced ferrite motor assembly</p></li><li><p>High sensitivity and linear frequency response</p></li><li><p>Advanced voice coil with flat copper clad aluminum wire</p></li></ul>', 'rosso-65cd-t', 'admin', 0, '', 0, '', '', '', 0, '/uploads/productimage/ROSSO-65CD-T.webp', '/uploads/productdrawing/ROSSO-65CD-T-drawing.jpg', '/uploads/productfrequencyresponse/ROSSO-65CD-T-frequency response.jpg', ''),
('02441977-f5ae-4146-8b01-7e45cff7eefc', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', '4\" SB12PACR-00 / Aluminum', 0, 0, 'ee5d459a-eaec-4159-9082-bdbe673a1ea4', '2024-05-03 07:14:40.811', '2025-12-10 08:14:52.138', '<ul><li><p>Vented reinforced plastic chassis</p></li><li><p>Anodised aluminium cone</p></li><li><p>Low damping rubber surround</p></li><li><p>Long stroke linear suspension</p></li><li><p>Easily adjustable moving mass</p></li></ul>', 'sb12pacr-00', 'admin', 0, '', 0, '', '', '', 1, '/uploads/productimage/4 inch SB12PACR-00.jpg', '/uploads/productdrawing/4 inch SB12PACR-00-drawing.jpg', '', ''),
('046ecd07-cbcb-4160-a4b1-729bc4bdf730', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', 'TW29DN / Fabric', 0, 0, '28c45742-6d1f-44bd-915b-f940e30caf92', '2024-05-08 04:14:20.098', '2026-05-28 06:58:47.448', '<ul><li><p>Large surround dome for increased acoustic output</p></li><li><p>Dual balanced compression chamber for improved dynamics</p></li><li><p>Dual copper caps for absolute minimum voice coil inductance and minimum phase shift</p></li><li><p>Two part aluminium faceplate with integrated mechanical decoupling</p></li><li><p>High saturation neodymium motor system with T-shaped pole piece for lower distortion</p></li><li><p>Non-reflective cast aluminium chamber with optimized damping for improved dynamics</p></li><li><p>Shallow flow optimized magnet structure for optimum coupling to rear chamber</p></li><li><p>CCAW voice coil for low moving mass</p></li><li><p>Long life silver lead wires</p></li><li><p>Low resonance frequency for extended range</p></li></ul>', 'tw29dn', 'admin', 0, '', 0, '', '', '', 1, '/uploads/productimage/SATORI TW29DN-1.jpg', '/uploads/productdrawing/SATORI TW29DN-drawing.jpg', '/uploads/productfrequencyresponse/SATORI TW29DN-frequency response.jpg', ''),
('06fc4fdb-9da4-40b1-8e2c-00ef3a30e74d', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', '8\" SB20PFCR30-4 / Paper', 0, 0, '3ceafaeb-f3e4-4034-b46a-44948d3c2062', '2024-05-06 02:22:49.269', '2026-03-02 06:24:56.489', '<ul><li><p>Vented reinforced plastic chassis</p></li><li><p>Proprietary cone material with natural fibers made in-house</p></li><li><p>Soft low damping rubber surround for improved transient response</p></li><li><p>Large spider for improved linearity</p></li><li><p>Optimized motor system</p></li><li><p>Vented coil former for low compression</p></li><li><p>Non-resonant long life lead wires</p></li></ul>', 'sb20pfcr30-4', 'admin', 0, '', 0, '', '', '', 1, '/uploads/productimage/8 inch SB20PFCR30-4-1.jpg', '/uploads/productdrawing/8 inch SB20PFCR30-4-drawing.jpg', '/uploads/productfrequencyresponse/8 inch SB20PFCR30-4-frequency response.jpg', ''),
('0870a243-a3a4-4cae-870b-c67745a004f7', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', 'TW29RN / Fabric', 0, 0, '28c45742-6d1f-44bd-915b-f940e30caf92', '2024-05-08 05:20:42.877', '2026-05-28 07:08:19.124', '<ul><li><p>Non-resonant diaphragm design for minimum high frequency break-up</p></li><li><p>Two part aluminium faceplate with integrated mechanical decoupling</p></li><li><p>Dual balanced compression chambers for improved dynamics</p></li><li><p>Dual copper caps for absolute minimum voice coil inductance and minimum phase shift</p></li><li><p>High saturation neodymium motor system with T-shaped pole piece for lower distortion</p></li><li><p>Non-reflective cast aluminium chamber with optimized damping for improved dynamics</p></li><li><p>Shallow flow optimized magnet structure for optimum coupling to rear chamber</p></li><li><p>CCAW voice coil for low moving mass</p></li><li><p>Long life silver lead wires</p></li><li><p>Low resonance frequency for extended range</p></li></ul>', 'tw29rn', 'admin', 0, '', 0, '', '', '', 1, '/uploads/productimage/SATORI TW29RN-1.jpg', '/uploads/productdrawing/SATORI TW29RN-drawing.jpg', '/uploads/productfrequencyresponse/SATORI TW29RN-frequency response.jpg', ''),
('0a1070aa-77fb-47a9-9bea-68a931f7c671', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', '12\" SB34NRX75-16 / Norex', 0, 0, 'afce813f-8a7d-424c-a086-9031ed369f64', '2024-05-03 07:35:36.341', '2025-12-15 10:06:40.905', '<ul><li><p>Designed for open baffle</p></li><li><p>High flow venting center pole</p></li><li><p>3″ CCAW voice coil</p></li><li><p>Low dampening surround</p></li><li><p>Non-inductive voice coil former</p></li><li><p>Proprietary cone materials made-in-house</p></li><li><p>Cast Aluminium chassis</p></li></ul>', 'sb34nrx75-16', 'admin', 0, '', 0, '', '', '', 1, '/uploads/productimage/12 inch SB34NRX75-16.jpg', '/uploads/productdrawing/12 inch SB34NRX75-16-drawing.jpg', '/uploads/productfrequencyresponse/12 inch SB34NRX75-16-frequency response.jpg', ''),
('0a22ed20-4f41-49aa-949d-51fd76627c56', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', '6\" SB16PFCR25-8 / Paper', 0, 0, 'ed8a91c0-2efb-4f49-892e-5f5cb123bd86', '2024-05-06 02:25:38.532', '2025-12-30 09:42:57.710', '<ul><li><p>Vented reinforced plastic chassis</p></li><li><p>Proprietary cone material with natural fibers made in-house</p></li><li><p>Soft low damping rubber surround for improved transient response</p></li><li><p>Optimized motor system</p></li><li><p>Vented coil former for low compression</p></li><li><p>Non-resonant long life lead wires</p></li></ul>', 'sb16pfcr25-8', 'admin', 0, '', 0, '', '', '', 1, '/uploads/productimage/6 inch SB16PFCR25-8-1.jpg', '/uploads/productdrawing/6 inch SB16PFCR25-8-drawing.jpg', '/uploads/productfrequencyresponse/6 inch SB16PFCR25-8-frequency response.jpg', ''),
('0b583ad8-c382-404a-b469-4da47fccc8ab', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', '6\" SB17NRX2C35-8 / Norex', 0, 0, 'ed8a91c0-2efb-4f49-892e-5f5cb123bd86', '2024-05-06 03:37:13.978', '2025-12-24 01:53:24.257', '<ul><li><p>Vented cast aluminum chassis for optimum strength and low compression</p></li><li><p>Proprietary cone material with natural fibers made in-house</p></li><li><p>Soft low damping rubber surround for transient response</p></li><li><p>Non-conducting fiber glass voice coil former for minimum damping</p></li><li><p>Extended copper sleeve on pole piece for low inductance and low distortion</p></li><li><p>Vented coil former</p></li><li><p>CCAW voice coil for reduced moving mass</p></li><li><p>Long life silver lead wires</p></li><li><p>Vented pole piece for reduced compression</p></li></ul>', 'sb17nrx2c35-8', 'admin', 0, '', 0, '', '', '', 1, '/uploads/productimage/6 inch SB17NRX2C35-8.jpg', '/uploads/productdrawing/6 inch SB17NRX2C35-8-drawing.jpg', '/uploads/productfrequencyresponse/6 inch SB17NRX2C35-8-frequency response.jpg', ''),
('0b61f122-f2df-4183-abc1-c602a0fae1b1', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', '6½\" MW16TX-8 / TeXtreme', 0, 0, '8dbb7e6d-2d6b-4e32-acc6-852e91b501e2', '2024-05-03 06:20:25.396', '2025-12-16 10:07:44.707', '<ul><li><p>Advanced TeXtreme® cone</p></li><li><p>Vented aerodynamic cast aluminium chassis</p></li><li><p>Soft low damping rubber surround</p></li><li><p>Advanced BIMAX spider</p></li><li><p>Powerful optimized low distortion neodymium motor system</p></li><li><p>Extended copper sleeve on pole piece</p></li><li><p>Non-conducting fiberglass voice coil former</p></li><li><p>Vented pole piece and voice coil</p></li><li><p>Light weight CCAW voice coil</p></li><li><p>Long life silver lead wires</p></li></ul>', 'mw16tx-8', 'admin', 0, '', 0, '', '', '', 1, '/uploads/productimage/6.5 inch SATORI MW16TX-8.jpg', '/uploads/productdrawing/6.5 inch SATORI MW16TX-8-drawing.jpg', '/uploads/productfrequencyresponse/6.5 inch SATORI MW16TX-8-frequency response.jpg', ''),
('0ce2bcc2-a925-45d8-a0e3-dd041103aa45', '9e2a9f31-bce3-48ff-b438-0a00f8f8ec0b', 'ROSSO-44CD-PK', 0, 0, '3aa615e1-7464-49b0-aefe-19cb5ab117df', '2025-09-15 07:36:47.927', '2026-04-17 04:09:56.793', '<ul><li><p>PEEK diaphragm</p></li><li><p>Optimized cast aluminum rear chamber with damping</p></li><li><p>Wide useful bandwidth</p></li><li><p>Smooth frequency and impedance response</p></li><li><p>Advanced voice coil with flat copper clad aluminum wire</p></li></ul>', 'rosso-44cd-pk', 'admin', 0, '', 0, '', '', '', 0, '/uploads/productimage/ROSSO-44CD-PK.webp', '/uploads/productdrawing/ROSSO-44CD-PK-drawing.jpg', '/uploads/productfrequencyresponse/ROSSO-44CD-PK-frequency response.jpg', ''),
('0e3c6f8c-1551-4f14-934a-b28389846ee6', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', '12\" SB34NRX-00 / Norex', 0, 0, 'afce813f-8a7d-424c-a086-9031ed369f64', '2024-05-06 03:46:20.311', '2025-12-10 10:24:06.887', '<ul><li><p>Hard paper cone for improved piston operation (made in-house)</p></li><li><p>Cast aluminium chassis for optimum strength</p></li><li><p>Low damping medium hardness rubber surround for improved dynamic linearity and mechanical stability</p></li><li><p>Easily adjustable moving mass</p></li></ul>', 'sb34nrx-00', 'admin', 0, '', 0, '', '', '', 1, '/uploads/productimage/12 inch SB34NRX-00.jpg', '/uploads/productdrawing/12 inch SB34NRX-00-drawing.jpg', '', ''),
('0e8d6ae2-e204-4dc1-afa0-3653135b61a2', '9e2a9f31-bce3-48ff-b438-0a00f8f8ec0b', 'ROSSO-6MW151D', 0, 0, '953070cb-3479-45cb-a809-b2209b9cfb79', '2026-04-17 07:28:27.344', '2026-05-29 08:43:25.313', '<ul><li><p>Cast aluminium chassis&nbsp;</p></li><li><p>Extended midrange performance&nbsp;</p></li><li><p>Minimum damping fiber glass voice coil former&nbsp;</p></li><li><p>Proprietary cone coating for controlled breakup&nbsp;</p></li><li><p>Shorting ring in motor system for reduced distortion&nbsp;</p></li><li><p>Proprietary cone paper material with manila pulp and graphite</p></li></ul>', 'rosso-6mw151d', 'admin', 1, '', 0, '', '', '', 0, '/uploads/productimage/ROSSO-6MW151D.webp', '/uploads/productdrawing/ROSSO-6MW151D-drawing-1.jpg', '/uploads/productfrequencyresponse/ROSSO-6MW151D-frequency response-1.jpg', ''),
('0eaae45c-f6e0-4880-9f90-90f6c6c271a5', '9e2a9f31-bce3-48ff-b438-0a00f8f8ec0b', 'BIANCO-10MW200', 0, 0, 'a0c5e6ff-7691-4ff5-b966-0a2b018cab59', '2025-09-17 05:43:49.929', '2026-05-29 08:39:12.813', '<ul><li><p>Proprietary cone paper material with linter pulp</p></li><li><p>2.4\" voice coil with APC (Advanced Polymer Coating)</p></li><li><p>Vented pole piece for reduced compression</p></li><li><p>Minimum damping fiber glass voice coil former</p></li><li><p>Weather-proof coated conepaper</p></li><li><p>Long life silver lead wires</p></li></ul>', 'bianco-10mw200', 'admin', 0, '', 0, '', '', '', 0, '/uploads/productimage/BIANCO-10MW200.webp', '/uploads/productdrawing/BIANCO-10MW200-drawing.jpg', '/uploads/productfrequencyresponse/BIANCO-10MW200-frequency response.jpg', ''),
('0ec4f7f4-7826-41d8-89d6-d92130988be3', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', 'Sasandu', 0, 0, '28c45742-6d1f-44bd-915b-f940e30caf92', '2024-05-08 02:13:49.854', '2026-04-29 07:49:24.567', '<p>The SASANDU is a large 3-way floor standing speaker showcasing the advanced SATORI 29mm Neodymium Beryllium tweeter. The midrange is covered by the <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" href=\"https://webdemosbe.xyz/products/mr16p-4\">6½″ SATORI MR16P-4</a> Egyptian Papyrus cone midrange with a dedicated large sealed midrange chamber for low compression and wonderful open midrange reproduction. Each speaker is solidly anchored in the lower octaves by two <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" href=\"https://webdemosbe.xyz/products/mw19p-8\">7½″ SATORI MW19P-8</a> for a deep, tight, and satisfyingly musical bass.</p><p>SASANDU also called Sasando means “sounded instrument” and is a traditional Indonesian harp like string instrument with a body made from bamboo and native type of leaves. The SASANDU is a no compromise speaker kit designed to reproduce music as faithfully as possible.</p><p>The SASANDU’s faceted baffle and optimized tweeter position to lower diffraction as well as inclined cabinet to time align the drivers result in state of the art imaging. The large high quality crossover has it’s own chamber behind the removable plinth.</p><p>The cabinet is masterfully crafted from 28, 18, and 15 mm MDF with strategic internal bracing to distribute cabinet vibrations and lower sound coloration. A slanted internal partition reduces internal standing waves and the over size 75 mm port at the rear ensures uncompressed bass even at very high listening levels.</p>', 'sasandu', 'admin', 0, '', 1, '', '2', 'Large 3-way Floor Standing Speaker Kit', 1, '/uploads/productimage/Sasandu.jpg', '/uploads/productdrawing/Sasandu-drawing.jpg', '', ''),
('112a0f3b-b019-482c-94d6-b021ac959b3a', '9e2a9f31-bce3-48ff-b438-0a00f8f8ec0b', 'ROSSO-18SW650', 0, 0, 'b62e324f-0673-485a-b51d-5a39a8f29196', '2025-09-17 07:23:25.884', '2026-05-29 08:46:24.203', '<ul><li><p>Proprietary cone paper material with silk cotton tree</p></li><li><p>Minimum damping fiber glass voice coil former</p></li><li><p>4\" voice coil with APC (Advanced Polymer Coating)</p></li><li><p>Ribbon voice coil wire for high efficiency</p></li><li><p>Cast aluminium chassis</p></li><li><p>Vented pole piece for reduced compression</p></li><li><p>Triple roll surround for extended excursion</p></li></ul>', 'rosso-18sw650', 'admin', 0, '', 0, '', '', '', 0, '/uploads/productimage/ROSSO-18SW650.webp', '/uploads/productdrawing/ROSSO-18SW650-drawing.jpg', '/uploads/productfrequencyresponse/ROSSO-18SW650-frequency response.jpg', ''),
('112acfc9-369e-424d-b146-8610e733aa73', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', '4\" SB12PFC25-4 / Paper', 0, 0, 'ee5d459a-eaec-4159-9082-bdbe673a1ea4', '2024-05-06 07:37:49.897', '2026-01-30 04:32:15.337', '<p><span style=\"color: rgb(230, 0, 19);\"><strong>To be discontinued from standard product range, available to OEM minimum order quantity 250 pcs.</strong></span></p><ul><li><p>Vented reinforced plastic chassis</p></li><li><p>Proprietary cone material with natural fibers made in-house</p></li><li><p>Butyl rubber surround for smooth frequency response</p></li><li><p>Vented motor system for low compression</p></li><li><p>Long stroke linear suspension for improved dynamics</p></li><li><p>Non-resonant long life lead wires</p></li></ul>', 'sb12pfc25-4', 'admin', 0, '', 0, '', '', '', 0, '/uploads/productimage/4 inch SB12PFC25-4.jpg', '/uploads/productdrawing/4 inch SB12PFC25-4-drawing.jpg', '/uploads/productfrequencyresponse/4 inch SB12PFC25-4-frequency response.jpg', ''),
