('243fad3a-e938-4617-83aa-0aa71484ed4c', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', 'SB26ADC-C000-4 / Aluminum', 0, 0, '28c45742-6d1f-44bd-915b-f940e30caf92', '2024-05-08 07:22:35.835', '2025-12-09 06:19:05.415', '<ul><li><p>Phase optimized diaphragm design for coherent high frequency radiation</p></li><li><p>Copper cap for reduced voice coil inductance and minimum phase shift</p></li><li><p>Saturation controlled motor system for low distortion</p></li><li><p>Non-reflective rear chamber with optimized damping for improved dynamics</p></li><li><p>Flow optimized vented pole piece for optimum coupling to rear chamber</p></li><li><p>CCAW voice coil for low moving mass</p></li><li><p>Long life silver lead wires</p></li><li><p>Low resonance frequency</p></li></ul>', 'sb26adc-c000-4', 'admin', 0, '', 0, '', '', '', 1, '/uploads/productimage/SB26ADC-C000-4-1.jpg', '/uploads/productdrawing/SB26ADC-C000-4-drawing.jpg', '/uploads/productfrequencyresponse/SB26ADC-C000-4-frequency response.jpg', ''),
('252b83c7-358e-4a6c-817c-2b35a7ac1a3a', '9e2a9f31-bce3-48ff-b438-0a00f8f8ec0b', 'BIANCO-44CD-PK', 0, 0, '3aa615e1-7464-49b0-aefe-19cb5ab117df', '2025-09-15 07:25:57.176', '2026-04-17 04:09:10.451', '<ul><li><p>PEEK diaphragm</p></li><li><p>Excellent frequency response</p></li><li><p>Smooth yet detailed and dynamic character</p></li><li><p>Extended upper frequency response</p></li><li><p>Advanced voice coil with Flat Copper Clad Aluminium Wire</p></li><li><p>Pust terminal for easy installation</p></li></ul>', 'bianco-44cd-pk', 'admin', 0, '', 0, '', '', '', 0, '/uploads/productimage/BIANCO-44CD-PK.webp', '/uploads/productdrawing/BIANCO-44CD-PK-drawing.jpg', '/uploads/productfrequencyresponse/BIANCO-44CD-PK-frequency response.jpg', ''),
('25848156-0bb7-4293-8f99-4dcc8ffb6eeb', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', 'DW50', 0, 0, '28c45742-6d1f-44bd-915b-f940e30caf92', '2024-05-08 03:26:35.858', '2026-05-29 03:46:51.360', '<p>Standard weight block designed to adjust the moving mass of SB Acoustics passive radiators.</p>', 'dw50', 'admin', 0, '', 1, '', '6', '', 1, '/uploads/productimage/DW50-1747897104737.jpg', '/uploads/productdrawing/DW50-drawing.jpg', '', ''),
('25a43b2f-bee7-4824-b5cd-64644d083053', '9e2a9f31-bce3-48ff-b438-0a00f8f8ec0b', 'BIANCO-8MWN150', 0, 0, '17a51e03-1662-47aa-9bdf-22c7a19751fb', '2025-09-17 04:10:22.479', '2026-05-29 08:40:50.117', '<ul><li><p>Proprietary cone paper material made in-house</p></li><li><p>Neodymium magnet</p></li><li><p>2.4\" voice coil with APC (Advanced Polymer Coating)</p></li><li><p>Minimum damping fiber glass voice coil former</p></li><li><p>CCAW voice coil wire for reduced moving mass</p></li><li><p>Vented pole piece for reduced compression</p></li><li><p>Long life silver lead wires</p></li></ul>', 'bianco-8mwn150', 'admin', 0, '', 0, '', '', '', 0, '/uploads/productimage/BIANCO-8MWN150.webp', '/uploads/productdrawing/BIANCO-8MWN150-drawing.jpg', '/uploads/productfrequencyresponse/BIANCO-8MWN150-frequency response.jpg', ''),
('26dbd4f2-0cdd-4aed-ac75-e45c5cacdd13', '9e2a9f31-bce3-48ff-b438-0a00f8f8ec0b', 'NERO-15OBN450D', 1, 0, '0829acf6-a413-48bd-98a3-de816ea9e77b', '2025-10-10 01:04:38.327', '2026-05-29 08:47:52.071', '<ul><li><p>Long stroke design</p></li><li><p>Designed for open baffle applications</p></li><li><p>Minimum damping fiber glass voice coil former</p></li><li><p>4\" CCAW voice coil using APC coating technology</p></li><li><p>Open Yoke Vent (OYV) for ultra low compression and noise</p></li><li><p>Large flared and vented pole piece for reduced compression</p></li><li><p>Extended copper sleeve for low inductance and intermodulation distortion</p></li><li><p>Proprietary cone paper material made in-house doped with fiberglass and graphene</p></li></ul>', 'nero-15obn450d', 'admin', 1, 'for more information, click the button below:', 0, '', '', '', 0, '/uploads/productimage/NERO-15OBN450D-1.webp', '/uploads/productdrawing/NERO-15OBN450D-drawing.jpg', '/uploads/productfrequencyresponse/NERO-15OBN450D-frequency response.jpg', '/uploads/featuredimages/NERO-15OBN450D-home cover.jpg.jpeg'),
('276d5bdc-dc52-4c77-bc77-6029b277992a', '9e2a9f31-bce3-48ff-b438-0a00f8f8ec0b', 'ROSSO-34CD-PK', 0, 0, '3aa615e1-7464-49b0-aefe-19cb5ab117df', '2025-09-15 07:02:59.800', '2026-04-17 04:07:58.031', '<ul><li><p>PEEK diaphragm</p></li><li><p>Optimized cast aluminium rear chamber with damping</p></li><li><p>Wide useful bandwidth</p></li><li><p>Smooth frequency and impedance response</p></li><li><p>Advanced voice coil with flat copper clad aluminum wire</p></li></ul>', 'rosso-34cd-pk', 'admin', 0, '', 0, '', '', '', 0, '/uploads/productimage/ROSSO-34CD-PK.webp', '/uploads/productdrawing/ROSSO-34CD-PK-drawing.jpg', '/uploads/productfrequencyresponse/ROSSO-34CD-PK-frequency response.jpg', ''),
('286000b2-ae7d-4403-80f3-47e6e2341700', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', 'SB21SDCN-C000-4 / Fabric', 0, 0, '28c45742-6d1f-44bd-915b-f940e30caf92', '2024-05-03 06:17:34.930', '2026-05-18 02:33:11.618', '<ul><li><p>Large surround dome for increased acoustic output</p></li><li><p>Copper cap for reduced voice coil inductance and minimum phase shift</p></li><li><p>Compact low distortion neodymium motor system</p></li><li><p>Non-resonant rear chamber with optimized damping for improved dynamics</p></li><li><p>CCAW voice coil for low moving mass</p></li><li><p>Long life silver lead wires</p></li><li><p>Low resonance frequency</p></li></ul>', 'sb21sdcn-c000-4', 'admin', 0, '', 0, '', '', '', 1, '/uploads/productimage/SB21SDCN-C000-4.jpg', '/uploads/productdrawing/SB21SDCN-C000-4-drawing.jpg', '/uploads/productfrequencyresponse/SB21SDCN-C000-4-frequency response.jpg', ''),
('28ff428d-f208-41ca-afea-6166d324a39b', '9e2a9f31-bce3-48ff-b438-0a00f8f8ec0b', 'ROSSO-15W400', 0, 0, '0829acf6-a413-48bd-98a3-de816ea9e77b', '2025-09-17 06:33:03.406', '2026-05-29 08:42:50.922', '<ul><li><p>Proprietary cone paper material witl silk cotton tree</p></li><li><p>Minimum damping fiber glass voice coil former</p></li><li><p>3\" voice coil with APC (Advanced Polymer Coating)</p></li><li><p>Ribbon voice coil wire for high efficiency</p></li><li><p>Cast aluminium chassis</p></li><li><p>Vented pole piece for reduced compression</p></li></ul>', 'rosso-15w400', 'admin', 0, '', 0, '', '', '', 0, '/uploads/productimage/ROSSO-15W400.webp', '/uploads/productdrawing/ROSSO-15W400-drawing.jpg', '/uploads/productfrequencyresponse/ROSSO-15W400-frequency response.jpg', ''),
('2ac23bad-e21f-4d60-b4e9-ef76522ee2c2', '9e2a9f31-bce3-48ff-b438-0a00f8f8ec0b', 'ROSSO-6C200D', 0, 0, '953070cb-3479-45cb-a809-b2209b9cfb79', '2026-04-17 08:44:24.013', '2026-05-29 08:43:01.105', '<ul><li><p>Cast aluminum chassis&nbsp;</p></li><li><p>Extended midrange performance&nbsp;</p></li><li><p>Pure carbon fiber cone made in house&nbsp;</p></li><li><p>Minimum damping fiber glass voice coil former&nbsp;</p></li><li><p>Shorting ring in motor system for reduced distortion&nbsp;</p></li><li><p>Proprietary cone coating for controlled breakup (rear side)</p></li></ul>', 'rosso-6c200d', 'admin', 1, '', 0, '', '', '', 0, '/uploads/productimage/ROSSO-6C200D.webp', '/uploads/productdrawing/ROSSO-6C200D-drawing-1.jpg', '/uploads/productfrequencyresponse/ROSSO-6C200D-frequency response-1.jpg', ''),
('2aec1332-ae71-4269-aa8f-218d4390d20e', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', '4\" SB12PFC25-8 / Paper', 0, 0, 'ee5d459a-eaec-4159-9082-bdbe673a1ea4', '2024-05-06 07:34:58.153', '2026-01-30 04:34:23.744', '<p><span style=\"color: rgb(230, 0, 19);\"><strong>To be discontinued from standard product range, available to OEM minimum order quantity 250 pcs.</strong></span></p><ul><li><p>Vented reinforced plastic chassis</p></li><li><p>Proprietary cone material with natural fibers made in-house</p></li><li><p>Butyl rubber surround for smooth frequency response</p></li><li><p>Vented motor system for low compression</p></li><li><p>Long stroke linear suspension for improved dynamics</p></li><li><p>Non-resonant long life lead wires</p></li></ul>', 'sb12pfc25-8', 'admin', 0, '', 0, '', '', '', 0, '/uploads/productimage/4 inch SB12PFC25-8-1747281333115.jpg', '/uploads/productdrawing/sb12pfc25-8-drawing-1753060067889.jpg', '/uploads/productfrequencyresponse/sb12pfc25-8-frequency-1753060067937.jpg', ''),
('2b8e1f02-40ad-43a8-a85d-0bb46a2c67b4', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', '10\" SB29NRX2-00 / Norex', 0, 0, '7f514f65-c75e-482d-bf43-66c4f8c08edc', '2024-04-18 07:16:30.898', '2025-12-10 10:16:59.230', '<ul><li><p>Hard paper cone for improved piston operation (made in-house)</p></li><li><p>Cast aluminum chassis for optimum strength</p></li><li><p>Low damping medium hardness rubber surround for improved dynamic linearity and mechanical stability</p></li><li><p>Easily adjustable moving mass</p></li></ul>', 'sb29nrx2-00', 'admin', 0, '', 0, '', '', '', 1, '/uploads/productimage/10 inch SB29NRX2-00.jpg', '/uploads/productdrawing/10 inch SB29NRX2-00-drawing.jpg', '', ''),
('2cdcd43e-d831-483f-bf55-1f04496274da', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', '6½\" MW16PNW-8 / Paper', 0, 0, '8dbb7e6d-2d6b-4e32-acc6-852e91b501e2', '2024-05-06 06:21:13.015', '2025-12-17 09:10:18.835', '<ul><li><p>Vented aerodynamic cast aluminium chassis for optimum strength and low compression</p></li><li><p>Proprietary cone material with EGYPTIAN PAPYRUS™ fibres made in-house</p></li><li><p>Soft low damping rubber surround for optimum transient response</p></li><li><p>Advanced BIMAX spider for improved linearity</p></li><li><p>Powerful optimized low distortion neodymium motor system</p></li><li><p>Non-conducting fibre glass voice coil former for minimum damping</p></li><li><p>Extended copper sleeve on pole piece for low inductance and reduced distortion</p></li><li><p>CCAW voice coil for reduced moving mass</p></li><li><p>Long life silver lead wires attached 180° apart for improved stability</p></li><li><p>Vented pole piece and coil former for reduced compression</p></li><li><p>Low piston to chassis diameter ratio</p></li><li><p>Gasket and bolt hole protrusions for reduced coupling to speaker cabinet</p></li></ul>', 'mw16pnw-8', 'admin', 0, '', 0, '', '', '', 1, '/uploads/productimage/6.5 inch SATORI MW16PNW-8.jpg', '/uploads/productdrawing/6.5 inch SATORI MW16PNW-8-drawing.jpg', '/uploads/productfrequencyresponse/6.5 inch SATORI MW16PNW-8-frequency response.jpg', '');
