('4b94a71f-d6f6-49cc-9b5e-3864f593113f', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', 'TW29R-B / Fabric', 0, 0, '28c45742-6d1f-44bd-915b-f940e30caf92', '2024-05-08 05:27:07.686', '2025-12-09 07:45:46.510', '<ul><li><p>Non-resonant diaphragm design for minimum high frequency break-up</p></li><li><p>Two part aluminium black faceplate with integrated mechanical decoupling</p></li><li><p>Dual balanced compression chambers for improved dynamics</p></li><li><p>Dual copper caps for absolute minimum voice coil inductance and minimum phase shift</p></li><li><p>Saturation controlled motor system with T-shaped pole piece for lower distortion</p></li><li><p>Non-reflective cast aluminium chamber with optimized damping for improved dynamics</p></li><li><p>Flow optimized vented pole piece for optimum coupling to rear chamber</p></li><li><p>CCAW voice coil for low moving mass</p></li><li><p>Long life silver lead wires</p></li><li><p>Low resonance frequency for extended range</p></li></ul>', 'tw29r-b', 'admin', 0, '', 0, '', '', '', 1, '/uploads/productimage/SATORI TW29R-B.jpg', '/uploads/productdrawing/SATORI TW29R-B-drawing.jpg', '/uploads/productfrequencyresponse/SATORI TW29R-B-frequency response.jpg', ''),
('4d4ea626-11b7-4ff9-b9f9-c5315c371428', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', 'WG29-187', 1, 0, '28c45742-6d1f-44bd-915b-f940e30caf92', '2026-04-01 07:26:28.475', '2026-05-29 06:44:37.730', '<ul><li><p>Suits all Satori TW29 models</p></li><li><p>Die cast aluminum waveguide</p></li><li><p>Screwless driver mounting</p></li><li><p>Adapter ring included</p></li><li><p>Smooth controlled directivity</p></li></ul><p></p><p><strong>Mounting Instructions</strong></p><ul><li><p>Undo the screws on the faceplate (2.5 mm Allen key)</p></li><li><p>Slowly and carefully remove the faceplate (excess glue at the edge of the diaphragm may stick to the back of the faceplate)</p></li><li><p>Use the same screws to mount the adapter ring on the tweeter</p></li><li><p>Insert the waveguide to the adapter ring</p></li><li><p>Fasten the four set screws (1.3 mm Allen key)</p></li></ul>', 'wg29-187', 'admin', 1, 'for more information, click the button below:', 0, '', '', '', 0, '/uploads/productimage/SATORI WG29-187-1.jpg', '/uploads/productdrawing/SATORI-WG29-187-drawing.jpg', '', '/uploads/featuredimages/SATORI WG29-187-home cover.webp'),
