('53006457-e0dd-4c8a-8117-17f9dc79b91e', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', 'TW29B-B / Beryllium', 0, 0, '28c45742-6d1f-44bd-915b-f940e30caf92', '2024-05-08 05:37:09.552', '2026-05-28 06:37:36.942', '<ul><li><p>Beryllium dome for non-resonant high frequency extension</p></li><li><p>Two part aluminium faceplate with integrated mechanical decoupling</p></li><li><p>Dual balanced compression chambers for improved dynamics</p></li><li><p>Dual copper caps for absolute minimum voice coil inductance and minimum phase shift</p></li><li><p>Non-reflective cast aluminium chamber with optimized damping for improved dynamics</p></li><li><p>CCAW voice coil for low moving mass</p></li><li><p>Long life silver lead wires</p></li><li><p>Low resonance frequency for extended range</p></li></ul>', 'tw29b-b', 'admin', 0, '', 0, '', '', '', 1, '/uploads/productimage/SATORI TW29B-B.jpg', '/uploads/productdrawing/SATORI TW29B-B-drawing.jpg', '/uploads/productfrequencyresponse/SATORI TW29B-B-frequency response.jpg', ''),
('53ee88b3-f165-4eda-b592-e3c7a8a61b9c', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', 'SB29SDNC-C000-4 / Fabric', 0, 0, '28c45742-6d1f-44bd-915b-f940e30caf92', '2024-05-03 04:06:19.453', '2026-05-18 02:33:49.097', '<ul><li><p>Large surround dome for increased acoustic output</p></li><li><p>CCAW voice coil for low moving mass</p></li><li><p>Long life silver lead wires</p></li><li><p>Low resonance frequency</p></li><li><p>Copper cap on pole piece for reduced voice coil inductance and minimum phase shift</p></li><li><p>Inherently shielded neodymium motor system</p></li><li><p>Internal pressure equalization and flow resistor for non-resonant coupling of cavities</p></li><li><p>Compact design</p></li></ul>', 'sb29sdnc-c000-4', 'admin', 0, '', 0, '', '', '', 1, '/uploads/productimage/SB29SDNC-C000-4.jpg', '/uploads/productdrawing/SB29SDNC-C000-4-drawing.jpg', '/uploads/productfrequencyresponse/SB29SDNC-C000-4-frequency response.jpg', ''),
('543daff1-930d-44d4-9372-4c8e84d083b0', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', '10\" SW26DAC76-3-DV / Aluminum', 0, 0, '7f514f65-c75e-482d-bf43-66c4f8c08edc', '2024-05-06 04:06:38.294', '2026-05-18 02:44:32.106', '<p><span style=\"color: rgb(230, 0, 19);\"><strong>To be discontinued from standard product range, available to OEM minimum order quantity 100 pcs</strong></span></p><ul><li><p>Unique patented long throw shallow design</p></li><li><p>Vented cast aluminum chassis for optimum strength and low compression</p></li><li><p>Dual rigid aluminum cone structure</p></li><li><p>Non-conducting fiber glass coil former for minimum damping</p></li><li><p>Shorting ring in motor system for reduced distortion</p></li><li><p>Copper voice coil for improved power handling</p></li><li><p>Dual voice coil</p></li><li><p>Long life insulated silver lead wires</p></li><li><p>Powerful neodymium motor system</p></li></ul>', 'sw26dac76-3-dv', 'admin', 0, '', 0, '', '', '', 1, '/uploads/productimage/10 inch SW26DAC76-3-DV-1.jpg', '/uploads/productdrawing/10 inch SW26DAC76-3-DV-drawing.jpg', '/uploads/productfrequencyresponse/10 inch SW26DAC76-3-DV-frequency response.jpg', ''),
