('5670580d-ec9d-4f9b-b7d1-f9b8f7c05e83', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', '5\" SB15NBAC30-4 / Aluminum', 0, 0, '5f43323d-d9ed-4688-8e2f-ff5247083128', '2024-04-23 08:44:52.905', '2025-12-19 10:02:18.264', '<ul><li><p>Vented cast aluminum chassis for optimum strength and low compression</p></li><li><p>Geometrically reinforced aluminum cone for optimum piston operation and reduced break-up</p></li><li><p>Soft low damping rubber surround for improved transient response</p></li><li><p>Non-conducting fibre glass voice coil former for minimum damping</p></li><li><p>Extended copper sleeve on pole piece for low inductance and low distortion</p></li><li><p>CCAW voice coil for reduced moving mass</p></li><li><p>Long life silver lead wires</p></li><li><p>Vented pole piece for reduced compression</p></li></ul>', 'sb15nbac30-4', 'admin', 0, '', 0, '', '', '', 1, '/uploads/productimage/5 inch SB15NBAC30-4-1.jpg', '/uploads/productdrawing/5 inch SB15NBAC30-4-drawing.jpg', '/uploads/productfrequencyresponse/5 inch SB15NBAC30-4-frequency response.jpg', '');
INSERT INTO `product` (`id`, `brandId`, `name`, `isFeatured`, `isArchived`, `sizeId`, `createdAt`, `updatedAt`, `description`, `slug`, `updatedBy`, `isNewProduct`, `featuredDesc`, `isKits`, `navbarNotes`, `priority`, `searchbox_desc`, `tempAllFinished`, `cover_img_url`, `drawing_img_url`, `graph_img_url`, `featured_img_url`) VALUES
('56808c9a-86fd-4eea-895e-1a60dc1b412c', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', '8\" SB20PFC30-4 / Paper', 0, 0, '3ceafaeb-f3e4-4034-b46a-44948d3c2062', '2024-05-03 06:28:53.762', '2026-01-08 07:59:04.393', '<p><span style=\"color: rgb(230, 0, 19);\"><strong>To be discontinued from standard product range, available to OEM minimum order quantity 250 pcs.</strong></span></p><ul><li><p>Vented reinforced plastic chassis</p></li><li><p>Proprietary cone material with natural fibers made in-house</p></li><li><p>Soft low damping rubber surround for improved transient response</p></li><li><p>Large spider for improved linearity</p></li><li><p>Optimized motor system</p></li><li><p>Vented coil former for low compression</p></li><li><p>Non-resonant long life lead wires</p></li></ul>', 'sb20pfc30-4', 'admin', 0, '', 0, '', '', '', 1, '/uploads/productimage/8 inch SB20PFC30-4.jpg', '/uploads/productdrawing/8 inch SB20PFC30-4-drawing.jpg', '/uploads/productfrequencyresponse/8 inch SB20PFC30-4-frequency response.jpg', ''),
('5794887a-cf7a-4805-887a-e3a87a0b78ad', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', 'Gema', 0, 0, '28c45742-6d1f-44bd-915b-f940e30caf92', '2024-05-08 03:04:15.455', '2026-05-22 09:04:43.815', '<p>Gema is a large 3-way speaker paying homage to the classic speaker of the 1970’s. Generous enclosure proportions fitted with large bass drivers were the bee’s knees at the time. And for good reason! The Gema is our take on a retro-styled speaker, and the much loved 12″ SB34NRXL75-8 lays the foundation of a deep, well controlled and tuneful bassline.</p><p>The dedicated midrange is covered from 680Hz and all the way up to 3kHz by the 4″ paper cone SB12MNRX2-25-4 which is characterized by good efficiency, low moving mass and great linearity resulting in excellent midrange clarity.</p><p>To perfectly match the articulate and open midrange the top end is handed over to the 1 inch soft dome SB26STAC-c000-4 equipped with die-cast aluminium faceplate, optimised rear chamber and full copper cap.</p><p>The well braced cabinet is designed with a large slot port tuned to 28 Hz opening to the front of the speaker and a generous sealed enclosure for the dedicated midrange. We highly recommend building the speakers from high quality 18mm plywood.</p><p>A good starting point for the placement of the Gema would be a spacing of 2.5-3 meters between the speakers with generous clearance to any side and rear walls and ideally on a stand or plinth elevating the speaker about 25cm from the floor and tilted back at about 6 degrees and a slight toe in. The tweeter and midrange are intended to be on the outside, but this will depend on the room – as usual, we encourage you to experiment with speaker placement to suit your taste and listening space.</p>', 'gema', 'admin', 0, 'for more information, click the button below:', 1, '', '1', 'Large 3-way Floor Standing Speaker Kit', 1, '/uploads/productimage/Gema.jpg', '/uploads/productdrawing/Gema-cabinet drawing.jpg', '', ''),
('57c2c915-77c8-489a-ae1f-1ea2c6d9f1ce', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', '6\" SB16PFC25-4-COAX / Paper', 0, 0, 'ed8a91c0-2efb-4f49-892e-5f5cb123bd86', '2024-05-06 06:59:42.196', '2026-02-10 06:01:29.105', '<p><span style=\"color: rgb(230, 0, 19);\"><strong>To be discontinued from standard product range, available to OEM minimum order quantity 200 pcs.</strong></span></p><ul><li><p>Vented reinforced plastic chassis</p></li><li><p>Proprietary cone material with natural fibers made in-house</p></li><li><p>Soft low damping rubber surround for improved transient response</p></li><li><p>Optimized motor system</p></li><li><p>Non-resonant long life lead wires</p></li><li><p>Compact large surround dome tweeter</p></li></ul>', 'sb16pfc25-4-coax', 'admin', 0, '', 0, '', '', '', 0, '/uploads/productimage/6 inch SB16PFC25-4-COAX.jpg', '/uploads/productdrawing/6 inch SB16PFC25-4-COAX-drawing.jpg', '/uploads/productfrequencyresponse/6 inch SB16PFC25-4-COAX-frequency response.jpg', ''),
('58c7adaa-0972-492d-93d6-a2160f00de30', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', '6½\" MW16PNW-4 / Paper', 0, 0, '8dbb7e6d-2d6b-4e32-acc6-852e91b501e2', '2024-05-06 06:27:14.626', '2025-12-17 08:35:36.494', '<ul><li><p>Vented aerodynamic cast aluminium chassis for optimum strength and low compression</p></li><li><p>Proprietary cone material with EGYPTIAN PAPYRUS™ fibres made in-house</p></li><li><p>Soft low damping rubber surround for optimum transient response</p></li><li><p>Advanced BIMAX spider for improved linearity</p></li><li><p>Powerful optimized low distortion neodymium motor system</p></li><li><p>Non-conducting fibre glass voice coil former for minimum damping</p></li><li><p>Extended copper sleeve on pole piece for low inductance and reduced distortion</p></li><li><p>CCAW voice coil for reduced moving mass</p></li><li><p>Long life silver lead wires attached 180° apart for improved stability</p></li><li><p>Vented pole piece and coil former for reduced compression</p></li><li><p>Low piston to chassis diameter ratio</p></li><li><p>Gasket and bolt hole protrusions for reduced coupling to speaker cabinet</p></li></ul>', 'mw16pnw-4', 'admin', 0, '', 0, '', '', '', 1, '/uploads/productimage/6.5 inch SATORI MW16PNW-4.jpg', '/uploads/productdrawing/6.5 inch SATORI MW16PNW-4-drawing.jpg', '/uploads/productfrequencyresponse/6.5 inch SATORI MW16PNW-4-frequency response.jpg', ''),
