('adb2b9b2-0513-412c-b569-eb66bb60e678', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', '2½\" SB65WBAC25-4 / Aluminum', 0, 0, '4f3df0be-01fa-438e-9c29-2afc3464a1fc', '2024-05-07 03:05:55.914', '2025-12-09 09:48:54.324', '<ul><li><p>Geometrically furrowed aluminum cone for extended usable frequency range</p></li><li><p>Copper cap for increased high frequency output, reduced phase shift at higher frequencies and improved power handling capability</p></li><li><p>Low damping surround and non-conductive voice coil former to ensure dynamics and an open/transparent sound character with excellent detailing/resolution</p></li><li><p>Linear neodymium motor system for reduced distortion</p></li><li><p>Vented voice coil former for reduced compression</p></li></ul>', 'sb65wbac25-4', 'admin', 0, '', 0, '', '', '', 1, '/uploads/productimage/2.5 inch SB65WBAC25-4.jpg', '/uploads/productdrawing/2.5 inch SB65WBAC25-4-drawing.jpg', '/uploads/productfrequencyresponse/2.5 inch SB65WBAC25-4-frequency response.jpg', ''),
