('ade1cb8f-227e-4150-b2df-b6510263cd42', '9e2a9f31-bce3-48ff-b438-0a00f8f8ec0b', 'NERO-10MWN600D', 0, 0, 'a0c5e6ff-7691-4ff5-b966-0a2b018cab59', '2025-09-17 05:48:46.486', '2026-05-29 08:41:03.970', '<ul><li><p>Proprietary cone paper material with manila pulp</p></li><li><p>Strong neodymium motor</p></li><li><p>3\" voice coil with APC (Advanced Polymer Coating)</p></li><li><p>Interleaved Sandwich Voice Coil technology</p></li><li><p>Cast aluminum chassis</p></li><li><p>Minimum damping fiber glass voice coil former</p></li><li><p>Copper sleeve for low inductance and reduced distortion</p></li><li><p>Vented motor for reduced compression</p></li></ul>', 'nero-10mwn600d', 'admin', 1, '', 0, '', '', '', 0, '/uploads/productimage/NERO-10MWN600D.webp', '/uploads/productdrawing/NERO-10MWN600D-drawing.jpg', '/uploads/productfrequencyresponse/NERO-10MWN600D-frequency response.jpg', ''),
('aeb7ba3b-f8a4-407b-ace5-18b785462f7a', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', 'SB26STWGC-4 / Fabric', 0, 0, '28c45742-6d1f-44bd-915b-f940e30caf92', '2024-05-08 05:53:49.113', '2025-12-09 06:17:03.950', '<ul><li><p>Solid aluminium waveguide</p></li><li><p>Controlled directivity</p></li><li><p>Adapter ring for bolt-less mounting to driver</p></li><li><p>Copper cap for reduced voice coil inductance and minimum phase shift</p></li><li><p>Non-reflective rear chamber with optimized damping for improved dynamics</p></li><li><p>Flow optimized vented pole piece for optimum coupling to rear chamber</p></li><li><p>Fine weave soft fabric dome for smooth frequency response</p></li><li><p>Saturation controlled motor system for low distortion</p></li><li><p>CCAW voice coil for low moving mass</p></li><li><p>Long life silver lead wires</p></li><li><p>Low resonance frequency</p></li></ul>', 'sb26stwgc-4', 'admin', 0, 'Custom Descriptions for \'SB26STWGC-4 / Fabric\'', 0, '', '', '', 1, '/uploads/productimage/SB26STWGC-4.jpg', '/uploads/productdrawing/SB26STWGC-4-drawing.jpg', '/uploads/productfrequencyresponse/SB26STWGC-4-frequency response.jpg', ''),
('af23ddde-c1ad-4414-8b20-19137aa4f162', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', '6½\" MW16PF-4 / Paper', 0, 0, '8dbb7e6d-2d6b-4e32-acc6-852e91b501e2', '2024-05-03 05:39:12.756', '2026-01-07 08:21:18.787', '<p><span style=\"color: rgb(230, 0, 19);\"><strong>To be discontinued from standard product range, available to OEM minimum order quantity 250 pcs.</strong></span></p><ul><li><p>Vented aerodynamic cast aluminium chassis for optimum strength and low compression.</p></li><li><p>Proprietary cone material with EGYPTIAN PAPYRUS™ fibres made in-house.</p></li><li><p>Soft low damping rubber surround for optimum transient response.</p></li><li><p>Advanced BIMAX spider for improved linearity.</p></li><li><p>Non-conducting fibre glass voice coil former for minimum damping.</p></li><li><p>Extended copper sleeve on pole piece for low inductance and reduced distortion.</p></li><li><p>CCAW voice coil for reduced moving mass.</p></li><li><p>Long life silver lead wires attached 180° apart for improved stability.</p></li><li><p>Vented pole piece and coil former for reduced compression.</p></li><li><p>Low piston to chassis diameter ratio.</p></li><li><p>Gasket and bolt hole protrusions for reduced coupling to speaker cabinet.</p></li></ul>', 'mw16pf-4', 'admin', 0, '', 0, '', '', '', 1, '/uploads/productimage/6.5 inch SATORI MW16PF-4.jpg', '/uploads/productdrawing/6.5 inch SATORI MW16PF-4-drawing.jpg', '/uploads/productfrequencyresponse/6.5 inch SATORI MW16PF-4-frequency response.jpg', ''),
('b059c81e-0bdb-4899-8b24-59854c2a6221', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', 'Sasandu TX', 0, 0, '28c45742-6d1f-44bd-915b-f940e30caf92', '2024-05-08 03:06:11.807', '2026-05-22 09:04:40.026', '<p>The SASANDU TX is a large 3-way floor standing speaker showcasing the SATORI TW29TXN-B-8 advanced TeXtreme® dome tweeter known for it’s extreme resolution and dynamics yet relaxed presentation. The midrange is covered by the 6½″ SATORI MW16TX-4 TeXtreme® cone midwoofer housed in a dedicated large sealed midrange chamber for low compression and wonderful open midrange. Each speaker is solidly anchored in the lower octaves by two 7½″ SATORI MW19TX-8 for a deep, tight and satisfyingly musical bass.</p><ul><li><p>Large 3-way floor standing speaker</p></li><li><p>Advanced TeXtreme High End SATORI drivers</p></li><li><p>Elegantly inclined cabinet for time alignment</p></li><li><p>Faceted baffle and optimized tweeter position for reduced diffraction</p></li><li><p>Slanted internal partition for reduced of standing waves</p></li><li><p>Stylish removable plinth for secure footing</p></li><li><p>Strategic internal bracing and dampening</p></li><li><p>Large low noise rear firing vent</p></li></ul>', 'sasandu-tx', 'admin', 0, 'for more information, click the button below:', 1, '', '3', 'Large 3-way Floor Standing Speaker Kit', 1, '/uploads/productimage/Sasandu Tx-3.jpg', '/uploads/productdrawing/Sasandu Tx-drawing-3.jpg', '', ''),
('b05e883e-9f11-4475-8f23-60edbea6df2b', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', '6\" SB16FRPC25-7 / Paper', 0, 0, 'ed8a91c0-2efb-4f49-892e-5f5cb123bd86', '2025-12-02 00:20:22.961', '2026-05-18 02:35:18.830', '<ul><li><p>Proprietary cone material with natural fibers made in-house</p></li><li><p>Light weight foam surround</p></li><li><p>Optimized whizzer cone for smooth high frequency extension</p></li><li><p>Phase plug for controlled radiation</p></li><li><p>Vented spider with flexibility control</p></li><li><p>Optimized motor system</p></li><li><p>Vented reinforced plastic chassis</p></li><li><p>Non-conductive coil former</p></li><li><p>Long life lead wires</p></li><li><p>Extended copper sleeve on pole piece</p></li></ul>', 'sb16frpc25-7', 'admin', 1, '', 0, '', '', '', 1, '/uploads/productimage/6 inch SB16FRPC25-7.jpg', '/uploads/productdrawing/6 inch SB16FRPC25-7-drawing.jpg', '/uploads/productfrequencyresponse/6 inch SB16FRPC25-7-frequency response.jpg', ''),
('b24acaf7-7324-40c7-83e6-58fd40bca891', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', '10\" SB26SFCL38-4 / Paper', 0, 0, '7f514f65-c75e-482d-bf43-66c4f8c08edc', '2024-05-07 03:25:21.212', '2025-12-16 08:11:18.879', '<ul><li><p>Hard pressed vented paper cone</p></li><li><p>Durable rubber surround</p></li><li><p>Symmetric suspension</p></li><li><p>Non-conductive coil former</p></li><li><p>Long life litz wires</p></li><li><p>Vented chassis</p></li><li><p>Bucking magnet</p></li></ul>', 'sb26sfcl38-4', 'admin', 0, '', 0, '', '', '', 1, '/uploads/productimage/10 inch SB26SFCL38-4-1.jpg', '/uploads/productdrawing/10 inch SB26SFCL38-4-drawing.jpg', '/uploads/productfrequencyresponse/10 inch SB26SFCL38-4-frequency response.jpg', ''),
('b38f32f9-5f36-4bd3-8c6e-24141ffbb375', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', 'Ara', 0, 0, '28c45742-6d1f-44bd-915b-f940e30caf92', '2024-05-08 02:55:33.903', '2026-04-28 01:15:32.382', '<p><strong>ARA</strong>, the smaller brother of <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" href=\"https://webdemosbe.xyz/products/rinjani\">RINJANI</a>, reflecting the same design concept. The ARA is a 2-way stand mount speaker kit based on the excellent SATORI drivers <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" href=\"https://webdemosbe.xyz/products/mw16p-4\">6½″ MW16P</a> Papyrus cone midwoofers and the famous <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" href=\"https://webdemosbe.xyz/products/tw29r-b\">SATORI TW29R</a> Ring-dome tweeter.</p><p>ARA is the highest point of Komodo Island in Indonesia and particularly notable as the habitat of the spectacular and mythical komodo dragons. The ARA kit is designed to deliver top level transparent and dynamic sound reproduction.</p><p>The ARA’s faceted baffle is specially designed to reduce high frequency diffraction and yield superb imaging qualities. A further 7° reclined cabinet ensures time alignment resulting in sublime staging and pin point placement of instruments.</p><p>The cabinet is masterfully crafted from 18 mm MDF with internal bracing to distribute cabinet vibrations and lower sound coloration. Unwanted reflections are minimized by wedge shaped inner rear walls. The ARA has a large rear firing port and high quality speaker terminals on a solid aluminium binding post plate.</p><p>For a larger speaker with similar design goals look to the <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" href=\"https://webdemosbe.xyz/products/rinjani\">RINJANI</a> and <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" href=\"https://webdemosbe.xyz/products/rinjani-be\">RINJANI Be</a> which are the larger floor standing siblings of the ARA.</p><p>Please see <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" href=\"https://webdemosbe.xyz/kits/open-source-kits\">Open Source Kits</a> for TeXtreme editions.</p>', 'ara', 'admin', 0, '', 1, '', '7', '2-way Bookshelf Speaker Kit', 0, '/uploads/productimage/Ara-1747894720006.jpg', '/uploads/productdrawing/ara-drawing-1753076844311.jpg', '', ''),
('b4d2a46c-1ae4-4b1d-bab6-f3e6fc687839', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', 'TW29DN-B-8 / Fabric', 0, 0, '28c45742-6d1f-44bd-915b-f940e30caf92', '2024-05-08 04:05:14.827', '2026-05-28 07:02:46.244', '<ul><li><p>Large surround dome for increased acoustic output</p></li><li><p>Dual balanced compression chamber for improved dynamics</p></li><li><p>Dual copper caps for absolute minimum voice coil inductance and minimum phase shift</p></li><li><p>Two part aluminium faceplate with integrated mechanical decoupling</p></li><li><p>Saturation controlled motor system with T-shaped pole piece for lower distortion</p></li><li><p>Non-reflective cast aluminium chamber with optimized damping for improved dynamics</p></li><li><p>Flow optimized vented pole piece for optimum coupling to rear chamber</p></li><li><p>CCAW voice coil for low moving mass</p></li><li><p>Long life silver lead wires</p></li><li><p>Low resonance frequency for extended range</p></li></ul>', 'tw29dn-b-8', 'admin', 0, '', 0, '', '', '', 1, '/uploads/productimage/SATORI TW29DN-B-8-1.jpg', '/uploads/productdrawing/SATORI TW29DN-B-8-drawing.jpg', '/uploads/productfrequencyresponse/SATORI TW29DN-B-8-frequency response.jpg', ''),
('b5b2ab0e-3e90-44d3-b969-7730a74be0dc', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', '6\" SB17NBAC35-8 / Aluminum', 0, 0, 'ed8a91c0-2efb-4f49-892e-5f5cb123bd86', '2024-04-23 09:07:44.999', '2026-04-07 06:35:12.476', '<ul><li><p>Vented cast aluminum chassis for optimum strength and low compression</p></li><li><p>Geometrically reinforced aluminum cone for optimum piston operation and reduced break-up</p></li><li><p>Soft low damping rubber surround for improved transient response</p></li><li><p>Non-conducting fibre glass voice coil former for minimum damping</p></li><li><p>Extended copper sleeve on pole piece for low inductance and low distortion</p></li><li><p>CCAW voice coil for reduced moving mass</p></li><li><p>Long life silver lead wires</p></li><li><p>Vented pole piece for reduced compression</p></li></ul>', 'sb17nbac35-8', 'admin', 0, '', 0, '', '', '', 1, '/uploads/productimage/6 inch SB17NBAC35-8-1.jpg', '/uploads/productdrawing/6 inch SB17NBAC35-8-drawing.jpg', '/uploads/productfrequencyresponse/6 inch SB17NBAC35-8-frequency response.jpg', '');
INSERT INTO `product` (`id`, `brandId`, `name`, `isFeatured`, `isArchived`, `sizeId`, `createdAt`, `updatedAt`, `description`, `slug`, `updatedBy`, `isNewProduct`, `featuredDesc`, `isKits`, `navbarNotes`, `priority`, `searchbox_desc`, `tempAllFinished`, `cover_img_url`, `drawing_img_url`, `graph_img_url`, `featured_img_url`) VALUES
('b6ee5250-51ae-4668-be49-ea76910e77e0', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', 'Micro-C', 0, 0, '28c45742-6d1f-44bd-915b-f940e30caf92', '2024-05-08 02:16:36.435', '2026-04-30 02:17:23.467', '<p>With the same external dimensions as the <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" href=\"https://webdemosbe.xyz/products/micro\">MICRO</a>, the MICRO-C features the high-end <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" href=\"https://webdemosbe.xyz/products/sb12cacs25-4\">4″ SB12CAC</a> ceramic cone midwoofer for truly exhilarating sound experiences. This speaker is capable of unbelievable detail and packs a real punch in the bass. We are enjoyed when we see peoples faces light up from the surprise of the musicality of this great speaker.</p><p><strong>Features:</strong></p><ul><li><p>High performance compact design</p></li><li><p>High End ceramic midwoofer</p></li><li><p>High quality cross-over</p></li><li><p>Front firing slot port</p></li><li><p>Versatile placement</p></li><li><p>Solid single-wiring binding posts</p></li></ul>', 'micro-c', 'admin', 0, 'Custom Descriptions for \'Micro-C\'', 1, '', '12', '2-way Compact Speaker Kit', 1, '/uploads/productimage/Micro C.jpg', '/uploads/productdrawing/Micro C-drawing.jpg', '', ''),
