('b81d3abc-fbec-4748-b7fc-6f54ae772028', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', 'TW29TXN-B / TeXtreme', 0, 0, '28c45742-6d1f-44bd-915b-f940e30caf92', '2024-05-08 04:02:47.784', '2026-03-02 06:07:08.982', '<ul><li><p>Advanced TeXtreme® dome</p></li><li><p>Two part aluminium faceplate with integrated mechanical decoupling</p></li><li><p>Dual balanced compression chambers for improved dynamics</p></li><li><p>Dual copper caps for absolute minimum voice coil inductance and minimum phase shift</p></li><li><p>High saturation neodymium motor system with T-shaped pole piece for lower distortion</p></li><li><p>Non-reflective cast aluminium chamber with optimized damping for improved dynamics</p></li><li><p>Shallow flow optimized magnet structure for optimum coupling to rear chamber</p></li><li><p>CCAW voice coil for low moving mass</p></li><li><p>Long life silver lead wires</p></li><li><p>Low resonance frequency for extended range</p></li></ul>', 'tw29txn-b', 'admin', 0, '', 0, '', '', '', 1, '/uploads/productimage/SATORI TW29TXN-B.jpg', '/uploads/productdrawing/SATORI TW29TXN-B-drawing.jpg', '/uploads/productfrequencyresponse/SATORI TW29TXN-B-frequency response.jpg', ''),
('b9c629fc-41d3-41c4-b09c-191b40bfbc8a', '9e2a9f31-bce3-48ff-b438-0a00f8f8ec0b', 'BIANCO-8MW250', 0, 0, '17a51e03-1662-47aa-9bdf-22c7a19751fb', '2025-09-17 04:00:32.666', '2026-05-29 08:40:40.298', '<ul><li><p>Smooth response and excellent bass</p></li><li><p>Vented pole piece for reduced compression</p></li><li><p>CCAW voice coil wire for reduced moving mass</p></li><li><p>Minimum damping fiber glass voice coil former</p></li><li><p>2\" voice coil with APC (Advanced Polymer Coating)</p></li><li><p>Weather-proof coated paper cone made in house with sisal and manila fibers</p></li></ul>', 'bianco-8mw250', 'admin', 1, '', 0, '', '', '', 0, '/uploads/productimage/BIANCO-8MW250.webp', '/uploads/productdrawing/BIANCO-8MW250-drawing.jpg', '/uploads/productfrequencyresponse/BIANCO-8MW250-frequency response.jpg', ''),
('baef526a-621a-489b-9d0b-d979d66c4c90', '9e2a9f31-bce3-48ff-b438-0a00f8f8ec0b', 'BIANCO-15SW400', 0, 0, '0829acf6-a413-48bd-98a3-de816ea9e77b', '2025-09-17 06:54:41.952', '2026-05-29 08:43:51.847', '<ul><li><p>Proprietary cone paper material with silk cotton tree</p></li><li><p>4\" voice coil with APC (Advanced Polymer Coating)</p></li><li><p>Cast aluminium chassis</p></li><li><p>Corrugation cone paper for improved durability</p></li><li><p>Minimum damping fiber glass voice coil former</p></li><li><p>Vented pole piece for reduced compression</p></li></ul>', 'bianco-15sw400', 'admin', 0, '', 0, '', '', '', 0, '/uploads/productimage/BIANCO-15SW400.webp', '/uploads/productdrawing/BIANCO-15SW400-drawing.jpg', '/uploads/productfrequencyresponse/BIANCO-15SW400-frequency response.jpg', ''),
