('bd586f2e-811c-45a9-8567-005087153d1b', '9e2a9f31-bce3-48ff-b438-0a00f8f8ec0b', 'ROSSO-21SW800', 0, 0, '9dc1041a-6061-4d3f-8d68-f12442a85f16', '2025-09-17 07:52:54.076', '2026-05-29 08:47:02.708', '<ul><li><p>Minimum damping fiber glass voice coil former</p></li><li><p>4.5\" voice coil with APC (Advanced Polymer Coating)</p></li><li><p>Ribbon voice coil wire for high efficiency</p></li><li><p>Cast aluminium chassis</p></li><li><p>Vented pole piece for reduced compression</p></li></ul>', 'rosso-21sw800', 'admin', 0, '', 0, '', '', '', 0, '/uploads/productimage/ROSSO-21SW800.webp', '/uploads/productdrawing/ROSSO-21SW800-drawing.jpg', '/uploads/productfrequencyresponse/ROSSO-21SW800-frequency response.jpg', ''),
('bed473a1-ca57-4738-8d51-72d1877ffefd', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', '4\" SB12PFCR25-4 / Paper', 0, 0, 'ee5d459a-eaec-4159-9082-bdbe673a1ea4', '2024-05-06 03:02:55.664', '2025-12-24 04:02:35.594', '<ul><li><p>Vented reinforced plastic chassis</p></li><li><p>Proprietary cone material with natural fibers made in-house</p></li><li><p>Butyl rubber surround for smooth frequency response</p></li><li><p>Vented motor system for low compression</p></li><li><p>Long stroke linear suspension for improved dynamics</p></li><li><p>Non-resonant long life lead wires</p></li></ul>', 'sb12pfcr25-4', 'admin', 0, '', 0, '', '', '', 1, '/uploads/productimage/4 inch SB12PFCR25-4-1.jpg', '/uploads/productdrawing/4 inch SB12PFCR25-4-drawing.jpg', '/uploads/productfrequencyresponse/4 inch SB12PFCR25-4-frequency response.jpg', ''),
