('e5dafc59-60c4-4879-ac29-7a75095b3317', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', 'TW29TXN-B-8 / TeXtreme', 0, 0, '28c45742-6d1f-44bd-915b-f940e30caf92', '2024-05-08 03:40:11.750', '2025-12-09 07:05:00.443', '<ul><li><p>Advanced TeXtreme® dome</p></li><li><p>Two part aluminium faceplate with integrated mechanical decoupling</p></li><li><p>Dual balanced compression chambers for improved dynamics</p></li><li><p>Dual copper caps for absolute minimum voice coil inductance and</p></li><li><p>minimum phase shift</p></li><li><p>High saturation neodymium motor system with T-shaped pole piece</p></li><li><p>for lower distortion</p></li><li><p>Non-reflective cast aluminium chamber with optimized damping for</p></li><li><p>improved dynamics</p></li><li><p>Shallow flow optimized magnet structure for optimum coupling to</p></li><li><p>rear chamber</p></li><li><p>CCAW voice coil for low moving mass</p></li><li><p>Long life silver lead wires</p></li><li><p>Low resonance frequency for extended range</p></li></ul>', 'tw29txn-b-8', 'admin', 0, '', 0, '', '', '', 1, '/uploads/productimage/SATORI TW29TXN-B-8.jpg', '/uploads/productdrawing/SATORI TW29TXN-B-8-drawing.jpg', '/uploads/productfrequencyresponse/SATORI TW29TXN-B-8-frequency response.jpg', ''),
('e5e925d5-570f-4b51-8db3-615556ca29cd', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', '5\" SB13PFC-00 / Paper', 0, 0, '5f43323d-d9ed-4688-8e2f-ff5247083128', '2024-05-03 06:10:09.842', '2026-01-09 09:33:03.116', '<p><span style=\"color: rgb(230, 0, 19);\"><strong>To be discontinued from standard product range, available to OEM minimum order quantity 250 pcs.</strong></span></p><ul><li><p>Vented reinforced plastic chassis</p></li><li><p>Proprietary cone material with natural fibers made in-house</p></li><li><p>Soft low damping surround</p></li><li><p>Easily adjustable moving mass</p></li><li><p>Symmetric suspension</p></li></ul>', 'sb13pfc-00', 'admin', 0, '', 0, '', '', '', 1, '/uploads/productimage/5 inch SB13PFC-00-1.jpg', '/uploads/productdrawing/5 inch SB13PFC-00-drawing.jpg', '', ''),
('e728bee8-f36f-427c-add3-41aa688804a0', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', 'TW29RN-B-8 / Fabric', 0, 0, '28c45742-6d1f-44bd-915b-f940e30caf92', '2024-05-08 03:51:19.045', '2026-05-28 07:10:11.551', '<ul><li><p>Non-resonant diaphragm design for minimum high frequency break-up</p></li><li><p>Two part aluminum faceplate with integrated mechanical decoupling</p></li><li><p>Dual balanced compression chambers for improved dynamics</p></li><li><p>Dual copper caps for absolute minimum voice coil inductance and minimum phase shift</p></li><li><p>High saturation neodymium motor system with T-shaped pole piece for lower distortion</p></li><li><p>Non-reflective cast aluminum chamber with optimized damping for improved dynamics</p></li><li><p>Shallow flow optimized magnet structure for optimum coupling to rear chamber</p></li><li><p>CCAW voice coil for low moving mass</p></li><li><p>Long life silver lead wires</p></li><li><p>Low resonance frequency for extended range</p></li></ul>', 'tw29rn-b-8', 'admin', 0, '', 0, '', '', '', 1, '/uploads/productimage/SATORI TW29RN-B-8-1.jpg', '/uploads/productdrawing/SATORI TW29RN-B-8-drawing.jpg', '/uploads/productfrequencyresponse/SATORI TW29RN-B-8-frequency response.jpg', ''),
('e7917dcf-bdbd-432e-8416-1333eaa0fc6d', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', 'SATORI 24 MAGNETIC GRILLE', 0, 0, '28c45742-6d1f-44bd-915b-f940e30caf92', '2024-05-08 03:18:45.280', '2026-02-10 08:32:32.022', '<p></p>', '24-magnetic-grille', 'admin', 0, '', 1, '', '5', '', 1, '/uploads/productimage/SATORI 24 magnetic grille.jpg', '/uploads/productdrawing/SATORI 24 Magnetic Grille-drawing.jpg', '', ''),
('e7d7b45a-b1b2-49d8-b18a-d77aeef653de', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', '10\" SW26DAC76-8 / Aluminum', 0, 0, '7f514f65-c75e-482d-bf43-66c4f8c08edc', '2024-05-06 04:10:09.289', '2026-01-08 10:28:38.285', '<p><span style=\"color: rgb(230, 0, 19);\"><strong>To be discontinued from standard product range, available to OEM minimum order quantity 100 pcs</strong></span></p><ul><li><p>Unique patented long throw shallow design</p></li><li><p>Vented cast aluminum chassis for optimum strength and low compression</p></li><li><p>Dual rigid aluminum cone structure</p></li><li><p>Non-conducting fiber glass coil former for minimum damping</p></li><li><p>Shorting ring in motor system for reduced distortion</p></li><li><p>Copper voice coil for improved power handling</p></li><li><p>Long life insulated silver lead wires</p></li><li><p>Powerful neodymium motor system</p></li></ul>', 'sw26dac76-8', 'admin', 0, '', 0, '', '', '', 1, '/uploads/productimage/10 inch SW26DAC76-8-1.jpg', '/uploads/productdrawing/10 inch SW26DAC76-8-drawing.jpg', '/uploads/productfrequencyresponse/10 inch SW26DAC76-8-frequency response.jpg', ''),
('e807adec-d1c2-42ad-a648-4952e7b0f0c2', '9e2a9f31-bce3-48ff-b438-0a00f8f8ec0b', 'BIANCO-12MW200', 0, 0, '945f368a-9dfa-4ba3-9bed-b93694e58de2', '2025-09-17 05:53:37.501', '2026-05-29 08:39:24.396', '<ul><li><p>Proprietary cone paper material with silk cotton tree and manila pulp</p></li><li><p>2.4\" voice coil with APC (Advanced Polymer Coating)</p></li><li><p>Vented pole piece for reduced compression</p></li><li><p>Minimum damping fiber glass voice coil former</p></li><li><p>Long life silver lead wires</p></li><li><p>Weather-proof coated conepaper</p></li></ul>', 'bianco-12mw200', 'admin', 0, '', 0, '', '', '', 0, '/uploads/productimage/BIANCO-12MW200.webp', '/uploads/productdrawing/BIANCO-12MW200-drawing.jpg', '/uploads/productfrequencyresponse/BIANCO-12MW200-frequency response.jpg', ''),
('e8b34f6a-9ab3-43bd-b822-f1e5b552abe5', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', 'SATORI 19 MAGNETIC GRILLE', 0, 0, '28c45742-6d1f-44bd-915b-f940e30caf92', '2024-05-08 03:19:54.765', '2026-02-10 08:26:37.413', '<p></p>', '19-magnetic-grille', 'admin', 0, '', 1, '', '4', '', 1, '/uploads/productimage/SATORI 19 magnetic grille.jpg', '/uploads/productdrawing/SATORI 19 Magnetic Grille-drawing.jpg', '', ''),
('e8eeb45d-1975-45ce-97b8-ae977c6c79a5', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', 'Raiya Tx', 1, 0, '28c45742-6d1f-44bd-915b-f940e30caf92', '2026-03-18 00:57:43.662', '2026-05-22 09:06:11.120', '<p>Introducing Raiya Tx — a new center channel designed to integrate seamlessly with the TeXtreme lineup, including Ara Tx, Rinjani Tx, and Sasandu Tx. Engineered for uncompromised full‑range performance and exceptional vocal intelligibility, Raiya Tx delivers dialogue with remarkable precision.</p><p>The vertically aligned midrange–tweeter eliminates the comb‑filtering artifacts that plague conventional horizontal centre-channel driver arrangements, producing a cleaner, more natural presentation across a wide listening area. Designed expressly for high‑end home theater systems, Raiya Tx ensures every word is conveyed with intent and accuracy.</p><p>With Raiya Tx, your cinematic soundscape gains a true focal point — refined, articulate, and perfectly matched to the TeXtreme family.</p>', 'raiya-tx', 'admin', 1, 'for more information, click the button below:', 1, '', '', '', 0, '/uploads/productimage/Raiya-main-picture.jpg', '/uploads/productdrawing/Raiya-drawing.jpg', '', '/uploads/featuredimages/Raiya Tx-home cover.webp'),
('e9babc62-1886-4347-9ea4-8b21b51eded0', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', 'TW29BN-B-8 / Beryllium', 0, 0, '28c45742-6d1f-44bd-915b-f940e30caf92', '2024-05-08 03:57:38.147', '2026-05-28 06:53:20.971', '<ul><li><p>Beryllium dome for non-resonant high frequency extension</p></li><li><p>Two part aluminium faceplate with integrated mechanical decoupling</p></li><li><p>Dual balanced compression chambers for improved dynamics</p></li><li><p>Dual copper caps for absolute minimum voice coil inductance and minimum phase shift</p></li><li><p>High saturation neodymium motor system with T-shaped pole piece for lower distortion</p></li><li><p>Non-reflective cast aluminium chamber with optimized damping for improved dynamics</p></li><li><p>Shallow flow optimized magnet structure for optimum coupling to rear chamber</p></li><li><p>CCAW voice coil for low moving mass</p></li><li><p>Long life silver lead wires</p></li><li><p>Low resonance frequency for extended range</p></li></ul>', 'tw29bn-b-8', 'admin', 0, '', 0, '', '', '', 1, '/uploads/productimage/SATORI TW29BN-B-8.jpg', '/uploads/productdrawing/SATORI TW29BN-B-8-drawing.jpg', '/uploads/productfrequencyresponse/SATORI TW29BN-B-8-frequency response.jpg', ''),
('ea265027-f6aa-4082-afb0-cccd175ed0e6', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', '7½\" MW19PNW-4 / Paper', 0, 0, '684c7a61-8852-4ac8-81b0-b059c3aa3ece', '2024-05-06 06:15:16.803', '2025-12-17 09:59:43.978', '<ul><li><p>Vented aerodynamic cast aluminium chassis for optimum strength and low compression</p></li><li><p>Proprietary cone material with EGYPTIAN PAPYRUS™ fibres made in-house</p></li><li><p>Soft low damping rubber surround for optimum transient response</p></li><li><p>Advanced BIMAX spider for improved linearity</p></li><li><p>Powerful optimized low distortion neodymium motor system</p></li><li><p>Non-conducting fibre glass voice coil former for minimum damping</p></li><li><p>Extended copper sleeve on pole piece for low inductance and reduced distortion</p></li><li><p>CCAW voice coil for reduced moving mass</p></li><li><p>Long life silver lead wires attached 180° apart for improved stability</p></li><li><p>Vented pole piece for reduced compression</p></li><li><p>Low piston to chassis diameter ratio</p></li><li><p>Gasket and bolt hole protrusions for reduced coupling to speaker cabinet</p></li></ul>', 'mw19pnw-4', 'admin', 0, 'Custom Descriptions for \'7½\" SATORI MW19PNW-4 / Paper\'', 0, '', '', '', 1, '/uploads/productimage/7.5 inch SATORI MW19PNW-8.jpg', '/uploads/productdrawing/7.5 inch SATORI MW19PNW-4-drawing.jpg', '/uploads/productfrequencyresponse/7.5 inch SATORI MW19PNW-4-frequency response.jpg', ''),
('eac993a2-a65d-4dad-a72e-468aee730d32', '9e2a9f31-bce3-48ff-b438-0a00f8f8ec0b', 'ROSSO-34CDN-PK', 0, 0, '3aa615e1-7464-49b0-aefe-19cb5ab117df', '2025-09-15 07:11:44.054', '2026-04-17 04:08:16.290', '<ul><li><p>PEEK diaphragm</p></li><li><p>Neodymium motor assembly</p></li><li><p>Optimized cast aluminum rear chamber with damping</p></li><li><p>High sensitivity</p></li><li><p>Wide useful bandwidth</p></li><li><p>Smooth frequency and impedance response</p></li><li><p>Screw on or bolt on with included adaptor</p></li><li><p>Advanced voice coil with flat copper clad aluminum wire</p></li></ul>', 'rosso-34cdn-pk', 'admin', 0, '', 0, '', '', '', 0, '/uploads/productimage/ROSSO-34CDN-PK.webp', '/uploads/productdrawing/ROSSO-34CDN-PK-drawing.jpg', '/uploads/productfrequencyresponse/ROSSO-34CDN-PK-frequency response.jpg', ''),
('ebe18f17-3c5e-4132-adb5-1a72759ea734', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', '4\" SB12NRX25-4 / Norex', 0, 0, 'ee5d459a-eaec-4159-9082-bdbe673a1ea4', '2024-05-06 08:32:57.169', '2025-12-22 06:06:36.566', '<ul><li><p>Proprietary cone material with natural fibres made in-house</p></li><li><p>High damping Butyl rubber surround for non-resonant sound character</p></li><li><p>Vented pole piece for reduced compression</p></li><li><p>Vented cast aluminium chassis for optimum strength and low compression</p></li><li><p>CCAW voice coil for reduced moving mass</p></li><li><p>Long life silver lead wires</p></li><li><p>Non-conducting fibre glass coil former for minimum damping</p></li><li><p>Shorting ring in motor system for reduced distortion</p></li></ul>', 'sb12nrx25-4', 'admin', 0, '', 0, '', '', '', 1, '/uploads/productimage/4 inch SB12NRX25-4-1.jpg', '/uploads/productdrawing/4 inch SB12NRX25-4-drawing.jpg', '/uploads/productfrequencyresponse/4 inch SB12NRX25-4-frequency response.jpg', ''),
