('ed39b62a-e410-4941-855e-66d68e1a83f1', '680c5eee-7ed7-41bc-b14b-4185f8a1c379', '4\" SB12PFC-00 / Paper', 0, 0, 'ee5d459a-eaec-4159-9082-bdbe673a1ea4', '2024-05-03 07:18:11.123', '2026-01-09 09:30:28.927', '<p><span style=\"color: rgb(230, 0, 19);\"><strong>To be discontinued from standard product range, available to OEM minimum order quantity 250 pcs.</strong></span></p><ul><li><p>Vented reinforced plastic chassis</p></li><li><p>Proprietary cone material with natural fibres made in-house</p></li><li><p>Low damping rubber surround</p></li><li><p>Long stroke linear suspension</p></li><li><p>Easily adjustable moving mass</p></li></ul>', 'sb12pfc-00', 'admin', 0, '', 0, '', '', '', 1, '/uploads/productimage/4 inch SB12PFC-00-1.jpg', '/uploads/productdrawing/4 inch SB12PFC-00-drawing.jpg', '', ''),
